type TargetType = "username" | "email" | "domain" | "ip" | "phone";
type Finding = { id: string; source: string; category: string; status: string; confidence: number; title: string; evidence: string; url?: string; compliance_flags: string[] };
type ProviderConfig = { id: string; name: string; category: string; source_id: string; target_types: string[]; status: string; connector_function: string; credential_refs: string[]; admin_section: string; proxy_route_supported: boolean; terms_note: string; data_returned: string[]; note: string };
type ApiKeyReference = { provider: string; provider_id: string; source_id: string; credential_type: string; connector_function: string; vault_reference: string; enabled: boolean; notes: string };
type SourceGate = { source_id: string; enabled: boolean; requires_approval: boolean; tenant_plan: string; note: string };
type GeneralSettingsState = { application_name: string; public_url: string; support_email: string; default_plan: string; require_consent: boolean; normalized_evidence_only: boolean; high_cost_provider_approval: boolean; export_retention_days: number };
type ProxySettingsState = { mode: "off" | "provider" | "manual"; manual_entries: string[]; use_only_for_allowlisted_egress: boolean; disable_failed_proxies: boolean; require_admin_approval: boolean; health_check_interval_minutes: number };
type ProxyRouteRule = { id: string; label: string; category: string; enabled: boolean; proxy_required: boolean; provider_ids: string[]; allowed_domains: string[]; note: string };
type ProxyConnectionResult = { index: number; proxy: string; ok: boolean; status: "connected" | "failed" | "invalid_format" | "skipped"; latency_ms?: number | null; http_status?: number | null; error: string; target_url: string };
type ProxyConnectionTestResponse = { ok: boolean; tested: number; connected: number; failed: number; target_url: string; results: ProxyConnectionResult[]; message: string };
type ContactSubmissionRecord = { id: string; name: string; email: string; company: string; message: string; status: string; received_at: string };
type AuditEvent = Record<string, string>;
type AuthResponse = { ok: boolean; role: "member" | "admin"; display_name: string; token: string; message: string };
type BillingPlan = { id: string; name: string; amount: number; currency: string; interval: "month" | "year" | "one_time"; monthly_search_limit: number; export_enabled: boolean; api_access_enabled: boolean; description: string; services: string[]; enabled: boolean; public: boolean; paypal_item_name: string; sort_order: number };
type PayPalSettingsState = { receiver_email: string; webhook_secret_ref: string; subscriptions_enabled: boolean; webhook_verified: boolean; currency: string; checkout_mode: "paypal_button" | "subscription" | "manual_invoice"; billing_contact_email: string; terms_url: string; success_url: string; cancel_url: string; plans: BillingPlan[] };

