const API_BASE_URL = import.meta.env.VITE_API_BASE_URL ?? "";
const PAYPAL_EMAIL = "techpronow@gmail.com";
const PAYPAL_URL = "https://www.paypal.com/cgi-bin/webscr?cmd=_xclick&business=techpronow%40gmail.com&currency_code=USD&item_name=Social%20Hunter%20SaaS";
async function api<T>(path: string, init?: RequestInit): Promise<T> {
  const token = localStorage.getItem("socialHunterToken");
  const headers: Record<string, string> = { "Content-Type": "application/json" };
  if (token) headers.Authorization = `Bearer ${token}`;
  const res = await fetch(`${API_BASE_URL}${path}`, { ...init, headers });
  const data = await res.json().catch(() => ({}));
  if (!res.ok) throw new Error(data.detail ?? `Request failed: ${path}`);
  return data as T;
}
const defaultBillingPlans: BillingPlan[] = [{ id: "starter", name: "Starter", amount: 49, currency: "USD", interval: "month", monthly_search_limit: 250, export_enabled: true, api_access_enabled: false, description: "Entry plan for small public-source research workflows.", services: ["250 searches per month", "Dashboard access", "JSON and CSV exports"], enabled: true, public: true, paypal_item_name: "Social Hunter Starter Plan", sort_order: 10 }, { id: "growth", name: "Growth", amount: 149, currency: "USD", interval: "month", monthly_search_limit: 1500, export_enabled: true, api_access_enabled: false, description: "Team plan for recurring account, domain, and contact verification workflows.", services: ["1,500 searches per month", "Member dashboard", "Report exports", "Provider health checks"], enabled: true, public: true, paypal_item_name: "Social Hunter Growth Plan", sort_order: 20 }, { id: "operator", name: "Operator", amount: 399, currency: "USD", interval: "month", monthly_search_limit: 7500, export_enabled: true, api_access_enabled: true, description: "Operator plan for higher-volume teams that need API access and advanced provider configuration.", services: ["7,500 searches per month", "API access", "Advanced source controls", "Audit and compliance exports"], enabled: true, public: true, paypal_item_name: "Social Hunter Operator Plan", sort_order: 30 }];
const recommendations = ["Add tenant-aware authentication with owner, analyst, billing, and read-only reviewer roles.", "Store provider credentials only as Vault-backed references and show health state, never raw keys.", "Use PayPal subscriptions plus verified webhooks before granting paid plan entitlements.", "Add audit logs for searches, exports, admin setting changes, and consent confirmations.", "Add source-level compliance controls by tenant, geography, provider, and use case.", "Add queued jobs, usage caps, and alerts so expensive enrichment APIs cannot be drained accidentally."];
const sampleFindings: Finding[] = [{ id: "1", source: "GitHub", category: "developer", status: "found", confidence: 0.86, title: "GitHub profile check", url: "https://github.com/socialhunter", evidence: "Demo fixture indicates a likely public profile.", compliance_flags: ["public_source", "no_bypass", "no_raw_secret"] }, { id: "2", source: "HIBP", category: "breach", status: "skipped", confidence: 0, title: "Breach lookup not enabled", evidence: "Add a Vault-backed API key and terms review before enabling live breach lookup.", compliance_flags: ["api_terms_required", "no_raw_secret"] }];
const fallbackSources = [{ id: "github", name: "GitHub Public Profiles", category: "username_profile", status: "ready" }, { id: "hunter", name: "Hunter.io", category: "email_intel", status: "needs_api_key" }, { id: "twilio", name: "Twilio Lookup", category: "phone_intel", status: "needs_api_key" }];
function routeFromPath(): Route { const p = window.location.pathname.replace(/\/+$/, ""); if (p.endsWith("/members")) return "members"; if (p.endsWith("/social-hunter-admin")) return "admin"; return "home"; }
function go(path: string) { window.history.pushState({}, "", path); window.dispatchEvent(new PopStateEvent("popstate")); }
function App() { const [route, setRoute] = React.useState<Route>(routeFromPath); const [menu, setMenu] = React.useState(false); React.useEffect(() => { const f = () => setRoute(routeFromPath()); window.addEventListener("popstate", f); return () => window.removeEventListener("popstate", f); }, []); return <><TopNav route={route} menu={menu} setMenu={setMenu} />{route === "home" && <Landing />}{route === "members" && <Members />}{route === "admin" && <Admin />}</>; }
function TopNav({ route, menu, setMenu }: { route: Route; menu: boolean; setMenu: (v: boolean) => void }) { const links = [["Home", "/"], ["Members", "/members/"], ["Pricing", "/#pricing"], ["About", "/#about"], ["Contact", "/#contact"]]; return <header className="floating-nav"><button className="brand-button" onClick={() => go("/")}><ShieldCheck size={22} />Social Hunter</button><nav className={menu ? "nav-links open" : "nav-links"}>{links.map(([label, href]) => <a key={label} href={href} className={(route === "members" && label === "Members") || (route === "home" && label === "Home") ? "active" : ""} onClick={(e) => { e.preventDefault(); setMenu(false); go(href); }}>{label}</a>)}</nav><button className="icon-button mobile-only" onClick={() => setMenu(!menu)}>{menu ? <X /> : <Menu />}</button></header>; }
function Landing() { const [plans, setPlans] = React.useState<BillingPlan[]>(defaultBillingPlans); React.useEffect(() => { api<BillingPlan[]>("/api/plans").then(setPlans).catch(() => undefined); }, []); return <main className="site-page"><section className="hero-section"><div className="hero-copy"><span className="eyebrow">Public-source intelligence for business teams</span><h1>Social Hunter</h1><p>Find, verify, and organize public contact, profile, domain, and company signals from approved APIs and public data sources.</p><div className="hero-actions"><button className="primary-button" onClick={() => go("/members/")}><UserRound size={18} />Member Login</button><a className="secondary-link" href="#pricing">View Pricing</a></div></div><ProductPreview /></section><section className="section-band" id="about"><SectionTitle eyebrow="Why clients use it" title="One workspace for compliant lead and account research." /><div className="benefit-grid"><Feature icon={<Search />} title="Find public signals" copy="Search usernames, emails, domains, phone numbers, IPs, and businesses from connected providers." /><Feature icon={<CheckCircle2 />} title="Validate before outreach" copy="Normalize records, score confidence, and separate verified results from weak signals." /><Feature icon={<Archive />} title="Export evidence" copy="Create clean reports for sales, recruiting, fraud review, and internal research workflows." /><Feature icon={<ShieldCheck />} title="Control compliance" copy="Keep sources gated by terms, consent, tenant plan, and admin-approved API credentials." /></div></section><section className="pricing-section" id="pricing"><SectionTitle centered eyebrow="Pricing" title="Simple monthly plans paid through PayPal." copy={`Payments route to ${PAYPAL_EMAIL}. Plan activation should be confirmed by admin until PayPal webhooks are connected.`} /><div className="pricing-grid">{plans.map((p) => <article className="price-card" key={p.id}><h3>{p.name}</h3><div className="price"><span>{`$${p.amount}`}</span>/{p.interval === "one_time" ? "once" : p.interval}</div><p>{p.description || `${p.monthly_search_limit.toLocaleString()} searches for lawful public-source research workflows.`}</p><ul className="price-services">{p.services.slice(0, 4).map((service) => <li key={service}>{service}</li>)}</ul><a className="primary-button full" href={`https://www.paypal.com/cgi-bin/webscr?cmd=_xclick&business=${encodeURIComponent(PAYPAL_EMAIL)}&currency_code=${p.currency}&item_name=${encodeURIComponent(p.paypal_item_name || `Social Hunter ${p.name} Plan`)}&amount=${p.amount}`} target="_blank" rel="noreferrer"><CreditCard size={18} />Pay with PayPal</a></article>)}</div></section><section className="section-band recommendations"><SectionTitle eyebrow="Strong recommendations" title="Six upgrades before selling this as a production SaaS." /><ol className="recommendation-list">{recommendations.map((r) => <li key={r}>{r}</li>)}</ol></section><section className="contact-section" id="contact"><div><span className="eyebrow">Contact</span><h2>Request access or ask about a team rollout.</h2><p>Form submissions appear in the admin contact mailbox after submission.</p></div><ContactForm /></section></main>; }
function ProductPreview() { return <div className="hero-dashboard"><div className="browser-bar"><span /><span /><span /></div><div className="preview-search"><Search size={18} /><span>domain: clientcompany.com</span><strong>92%</strong></div><div className="preview-grid"><Metric label="Profiles checked" value="184" /><Metric label="Verified emails" value="37" /><Metric label="Risk flags" value="6" /></div><div className="preview-list"><Preview label="GitHub public profile" status="found" /><Preview label="Business records" status="found" /><Preview label="HIBP exposure check" status="review" /></div></div>; }
function SectionTitle({ eyebrow, title, copy, centered }: { eyebrow: string; title: string; copy?: string; centered?: boolean }) { return <div className={centered ? "section-heading centered" : "section-heading"}><span className="eyebrow">{eyebrow}</span><h2>{title}</h2>{copy && <p>{copy}</p>}</div>; }
function Feature({ icon, title, copy }: { icon: React.ReactNode; title: string; copy: string }) { return <article className="feature-card">{icon}<h3>{title}</h3><p>{copy}</p></article>; }
function Metric({ label, value }: { label: string; value: string }) { return <div><strong>{value}</strong><span>{label}</span></div>; }
function Preview({ label, status }: { label: string; status: string }) { return <div className="preview-row"><span>{label}</span><strong>{status}</strong></div>; }
function ResetPasswordPanel({ role, endpoint, placeholder }: { role: "member" | "admin"; endpoint: string; placeholder: string }) { const [email, setEmail] = React.useState(""); const [status, setStatus] = React.useState<"idle" | "sending" | "sent" | "error">("idle"); const [message, setMessage] = React.useState(""); async function requestReset(e: React.FormEvent) { e.preventDefault(); setStatus("sending"); setMessage(""); try { const res = await fetch(`${API_BASE_URL}${endpoint}`, { method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify({ email }) }); const data = await res.json().catch(() => ({})); if (!res.ok) throw new Error(data.detail ?? "Password reset request failed"); setStatus("sent"); setMessage(data.message ?? "Password reset email request queued."); } catch (err) { setStatus("error"); setMessage(err instanceof Error ? err.message : "Password reset request failed"); } } return <form className="reset-panel" onSubmit={requestReset}><div><Mail size={22} /><div><strong>Reset {role} password by email</strong><span>Enter the email on the account and the reset workflow will send instructions once mail is configured.</span></div></div><label>Email address<input required type="email" value={email} onChange={(e) => setEmail(e.target.value)} placeholder={placeholder} autoComplete="email" /></label><button className="secondary-button full" disabled={status === "sending"}><Mail size={18} />{status === "sending" ? "Sending reset request" : "Email reset instructions"}</button>{message && <p className={status === "error" ? "error-state" : "success-state"}>{message}</p>}</form>; }
function Members() { const [signedIn, setSignedIn] = React.useState(localStorage.getItem("socialHunterRole") === "member"); const [view, setView] = React.useState<MemberView>("dashboard"); const [login, setLogin] = React.useState({ username: "member", password: "member" }); const [error, setError] = React.useState(""); async function submit(e: React.FormEvent) { e.preventDefault(); setError(""); try { const auth = await api<AuthResponse>("/api/auth/member/login", { method: "POST", body: JSON.stringify(login) }); localStorage.setItem("socialHunterToken", auth.token); localStorage.setItem("socialHunterRole", auth.role); setSignedIn(true); } catch (err) { setError(err instanceof Error ? err.message : "Sign in failed"); } } if (signedIn) return <MemberDashboard view={view} setView={setView} />; return <main className="auth-page"><section className="auth-layout"><div className="auth-panel"><span className="eyebrow">Members</span><h1>Sign in to your dashboard</h1><form className="form-stack" onSubmit={submit}><label>Username or email<input required autoComplete="username" placeholder="member@example.com" value={login.username} onChange={(e) => setLogin({ ...login, username: e.target.value })} /></label><label>Password<input required type="password" autoComplete="current-password" placeholder="Password" value={login.password} onChange={(e) => setLogin({ ...login, password: e.target.value })} /></label><button className="primary-button full"><LockKeyhole size={18} />Sign in</button>{error && <p className="error-state">{error}</p>}</form><ResetPasswordPanel role="member" endpoint="/api/auth/member/password-reset" placeholder="member@example.com" /></div><div className="signup-panel"><UserPlus size={30} /><h2>Need an account?</h2><p>Create a member request and choose the plan that fits your search volume.</p><form className="form-stack"><label>Name<input placeholder="Your name" /></label><label>Email<input type="email" placeholder="you@company.com" /></label><label>Plan<select defaultValue="Growth"><option>Starter</option><option>Growth</option><option>Operator</option></select></label><a className="secondary-button full" href={PAYPAL_URL} target="_blank" rel="noreferrer"><CreditCard size={18} />Continue to PayPal</a></form></div></section></main>; }function Admin() { const [signedIn, setSignedIn] = React.useState(localStorage.getItem("socialHunterRole") === "admin"); const [view, setView] = React.useState<AdminView>("overview"); const [login, setLogin] = React.useState({ username: "admin", password: "admin" }); const [error, setError] = React.useState(""); async function submit(e: React.FormEvent) { e.preventDefault(); setError(""); try { const auth = await api<AuthResponse>("/api/auth/admin/login", { method: "POST", body: JSON.stringify(login) }); localStorage.setItem("socialHunterToken", auth.token); localStorage.setItem("socialHunterRole", auth.role); setSignedIn(true); } catch (err) { setError(err instanceof Error ? err.message : "Admin sign in failed"); } } if (signedIn) return <AdminDashboard view={view} setView={setView} />; return <main className="auth-page"><section className="auth-panel admin-login"><span className="eyebrow">Admin</span><h1>Social Hunter Admin</h1><p>Restricted configuration gateway for platform operators.</p><form className="form-stack" onSubmit={submit}><label>Admin username<input required autoComplete="username" value={login.username} onChange={(e) => setLogin({ ...login, username: e.target.value })} /></label><label>Password<input required type="password" autoComplete="current-password" value={login.password} onChange={(e) => setLogin({ ...login, password: e.target.value })} /></label><button className="primary-button full"><LockKeyhole size={18} />Enter admin dashboard</button>{error && <p className="error-state">{error}</p>}</form><ResetPasswordPanel role="admin" endpoint="/api/auth/admin/password-reset" placeholder="admin@example.com" /></section></main>; }function useWorkspace() { const [targetType, setTargetType] = React.useState<TargetType>("username"); const [target, setTarget] = React.useState("socialhunter"); const [consent, setConsent] = React.useState(true); const [findings, setFindings] = React.useState<Finding[]>(sampleFindings); const [selectedId, setSelectedId] = React.useState("1"); const [sources, setSources] = React.useState(fallbackSources); const [category, setCategory] = React.useState("all"); const [loading, setLoading] = React.useState(false); const [error, setError] = React.useState(""); React.useEffect(() => { fetch(`${API_BASE_URL}/api/sources`).then((r) => r.json()).then(setSources).catch(() => undefined); }, []); async function runSearch(e: React.FormEvent) { e.preventDefault(); setLoading(true); setError(""); try { const res = await fetch(`${API_BASE_URL}/api/search`, { method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify({ target_type: targetType, target, consent_confirmed: consent, dry_run: true }) }); if (!res.ok) throw new Error("Search failed"); const data = await res.json(); setFindings(data.findings ?? sampleFindings); setSelectedId((data.findings ?? sampleFindings)[0]?.id ?? ""); } catch (err) { setError(err instanceof Error ? err.message : "Search failed"); } finally { setLoading(false); } } function exportReport(format: string) { const blob = new Blob([JSON.stringify({ target, findings, format }, null, 2)], { type: "application/json" }); const url = URL.createObjectURL(blob); const a = document.createElement("a"); a.href = url; a.download = `social-hunter-${format}.json`; a.click(); URL.revokeObjectURL(url); } const categories = ["all", ...Array.from(new Set(findings.map((f) => f.category)))]; const results = category === "all" ? findings : findings.filter((f) => f.category === category); const selected = results.find((f) => f.id === selectedId) ?? results[0]; return { targetType, setTargetType, target, setTarget, consent, setConsent, findings, selectedId, setSelectedId, sources, category, setCategory, loading, error, runSearch, exportReport, categories, results, selected }; }
function Shell({ title, subtitle, nav, active, onNav, children }: { title: string; subtitle: string; nav: { id: string; label: string; icon: React.ReactNode }[]; active: string; onNav: (id: string) => void; children: React.ReactNode }) { return <main className="app-shell"><aside className="sidebar"><button className="brand side-brand" onClick={() => go("/")}><ShieldCheck size={24} />Social Hunter</button><nav>{nav.map((item) => <button key={item.id} className={active === item.id ? "nav-item active" : "nav-item"} onClick={() => onNav(item.id)}>{item.icon}{item.label}</button>)}</nav><div className="policy-box"><strong>Controlled workspace</strong><span>Approved sources, tenant controls, and evidence-first reporting.</span></div></aside><section className="workspace"><header className="topbar"><div><h1>{title}</h1><p>{subtitle}</p></div><button className="operator" onClick={() => go("/")}><UserRound size={18} />Exit</button></header>{children}</section></main>; }
function MemberDashboard({ view, setView }: { view: MemberView; setView: (v: MemberView) => void }) { const w = useWorkspace(); return <Shell title="Member Dashboard" subtitle="Run searches, review reports, and monitor enabled data sources." nav={[{ id: "dashboard", label: "Dashboard", icon: <Gauge size={18} /> }, { id: "search", label: "Search", icon: <Search size={18} /> }, { id: "reports", label: "Reports", icon: <Archive size={18} /> }, { id: "sources", label: "Sources", icon: <Database size={18} /> }]} active={view} onNav={(id) => setView(id as MemberView)}>{view === "dashboard" && <MemberOverview w={w} />}{view === "search" && <SearchWorkspace w={w} />}{view === "reports" && <ReportsView w={w} />}{view === "sources" && <SourcesView sources={w.sources} />}</Shell>; }
function AdminDashboard({ view, setView }: { view: AdminView; setView: (v: AdminView) => void }) { const w = useWorkspace(); return <Shell title="Admin Dashboard" subtitle="Configure SaaS settings, provider credentials, proxy lists, mail, billing, users, and audit controls." nav={[{ id: "overview", label: "Overview", icon: <Gauge size={18} /> }, { id: "general", label: "General Settings", icon: <Settings size={18} /> }, { id: "api", label: "API Keys", icon: <KeyRound size={18} /> }, { id: "proxy", label: "Proxy Config", icon: <Network size={18} /> }, { id: "mail", label: "Contact Mail", icon: <Mail size={18} /> }, { id: "users", label: "Users", icon: <UsersRound size={18} /> }, { id: "billing", label: "Billing", icon: <CreditCard size={18} /> }, { id: "audit", label: "Audit", icon: <Activity size={18} /> }]} active={view} onNav={(id) => setView(id as AdminView)}>{view === "overview" && <AdminOverview w={w} />}{view === "general" && <GeneralSettings />}{view === "api" && <ApiSettings />}{view === "proxy" && <ProxySettings />}{view === "mail" && <ContactMail />}{view === "users" && <UsersPage />}{view === "billing" && <BillingPage />}{view === "audit" && <AuditPage />}</Shell>; }
function MemberOverview({ w }: { w: Workspace }) { return <section className="dashboard-grid single"><div className="metric-strip cards"><Metric label="Searches this month" value="184" /><Metric label="Reports exported" value="29" /><Metric label="Enabled sources" value={String(w.sources.filter((s) => s.status !== "disabled").length)} /></div><section className="content-panel"><SectionTitle eyebrow="Recent search" title={w.target} copy="Latest normalized source results." /><FindingsTable results={w.findings} selectedId={w.selectedId} setSelectedId={w.setSelectedId} /></section></section>; }
function SearchWorkspace({ w }: { w: Workspace }) { const found = w.results.filter((f) => f.status === "found").length; const review = w.results.filter((f) => f.status === "unknown" || f.status === "skipped").length; return <><section className="search-panel"><form onSubmit={w.runSearch}><div className="tabs">{(["username", "email", "domain", "ip", "phone"] as TargetType[]).map((t) => <button type="button" key={t} className={w.targetType === t ? "tab active" : "tab"} onClick={() => w.setTargetType(t)}>{t}</button>)}</div><div className="search-row"><label>Target<input value={w.target} onChange={(e) => w.setTarget(e.target.value)} placeholder="username, email, domain, IP, or phone" /></label><button className="primary-button" disabled={w.loading}><Search size={18} />{w.loading ? "Searching" : "Run search"}</button></div><label className="consent-row"><input type="checkbox" checked={w.consent} onChange={(e) => w.setConsent(e.target.checked)} />Authorized business or educational use confirmed</label>{w.error && <div className="error-state">{w.error}</div>}</form></section><section className="dashboard-grid"><section className="results-panel"><div className="metric-strip"><Metric label="Checks" value={String(w.results.length)} /><Metric label="Found" value={String(found)} /><Metric label="Review" value={String(review)} /></div><div className="filter-row"><span>Category</span>{w.categories.map((c) => <button key={c} className={w.category === c ? "mini-tab active" : "mini-tab"} onClick={() => w.setCategory(c)}>{c}</button>)}</div><FindingsTable results={w.results} selectedId={w.selectedId} setSelectedId={w.setSelectedId} /></section><EvidencePanel selected={w.selected} exportReport={w.exportReport} /></section></>; }
function FindingsTable({ results, selectedId, setSelectedId }: { results: Finding[]; selectedId: string; setSelectedId: (id: string) => void }) { return <div className="table-wrap"><table><thead><tr><th>Source</th><th>Category</th><th>Status</th><th>Confidence</th></tr></thead><tbody>{results.map((f) => <tr key={f.id} className={f.id === selectedId ? "selected" : ""} onClick={() => setSelectedId(f.id)}><td>{f.source}</td><td>{f.category}</td><td><span className={`status ${f.status}`}>{f.status.replace("_", " ")}</span></td><td>{Math.round(f.confidence * 100)}%</td></tr>)}</tbody></table></div>; }
function EvidencePanel({ selected, exportReport }: { selected?: Finding; exportReport: (f: string) => void }) { if (!selected) return <aside className="detail-panel"><p className="empty-state">Select a finding to inspect evidence.</p></aside>; return <aside className="detail-panel"><div className="detail-header"><Activity size={20} /><div><h2>{selected.title}</h2><p>{selected.source}</p></div></div><div className="confidence"><span>Confidence</span><strong>{Math.round(selected.confidence * 100)}%</strong></div><p className="evidence">{selected.evidence}</p>{selected.url && <a className="source-link" href={selected.url} target="_blank" rel="noreferrer">Open source URL</a>}<div className="flag-list">{selected.compliance_flags.map((flag) => <span key={flag}>{flag.replaceAll("_", " ")}</span>)}</div><div className="button-row"><button className="secondary-button" onClick={() => exportReport("json")}><FileDown size={18} />JSON</button><button className="secondary-button" onClick={() => exportReport("csv")}><FileDown size={18} />CSV</button></div></aside>; }
function ReportsView({ w }: { w: Workspace }) { return <section className="content-panel"><SectionTitle eyebrow="Reports" title="Latest report package" copy="Export normalized evidence for review." /><div className="report-grid"><Metric label="Target" value={w.target} /><Metric label="Findings" value={String(w.findings.length)} /><Metric label="Generated" value={new Date().toLocaleString()} /></div><div className="button-row left"><button className="primary-button" onClick={() => w.exportReport("json")}><FileDown size={18} />Export JSON</button><button className="secondary-button compact" onClick={() => w.exportReport("csv")}>Export CSV</button></div></section>; }
function SourcesView({ sources }: { sources: typeof fallbackSources }) { return <section className="content-panel"><div className="source-list">{sources.map((s) => <article className="source-card" key={s.id}><div><h2>{s.name}</h2><p>Provider category: {s.category}. Keep enabled only when terms, consent, and credentials are approved.</p></div><span className={`status ${s.status}`}>{s.status.replaceAll("_", " ")}</span><dl><dt>Category</dt><dd>{s.category}</dd><dt>Storage</dt><dd>Normalized evidence only</dd></dl></article>)}</div></section>; }
function AdminOverview({ w }: { w: Workspace }) { return <section className="admin-grid"><article className="content-panel"><SectionTitle eyebrow="Admin" title="Launch checklist" /><ul className="check-list"><li><strong>Dashboard UI</strong> - done: public, member, and admin surfaces are present.</li><li><strong>Authentication</strong> - partial: forms exist; backend auth needs wiring.</li><li><strong>Billing</strong> - partial: PayPal links exist; webhooks need wiring.</li><li><strong>Provider keys</strong> - done: provider catalog, Vault references, source gates, save, and test endpoints are wired.</li><li><strong>Proxy controls</strong> - done: import, validation, route rules, and save endpoints are wired.</li></ul></article><article className="content-panel"><SectionTitle eyebrow="Contract" title="Engine controls" /><div className="contract-box"><LockKeyhole size={18} /><span>Use approved APIs and public sources. Keep provider credentials in Vault references only.</span></div></article><article className="content-panel wide"><SectionTitle eyebrow="Readiness" title={`${w.sources.length} source slots`} /><div className="readiness-row">{w.sources.map((s) => <span className={`status ${s.status}`} key={s.id}>{s.name}: {s.status.replaceAll("_", " ")}</span>)}</div></article></section>; }
function SettingsPanel({ title, children }: { title: string; children: React.ReactNode }) { return <section className="content-panel settings-panel"><SectionTitle eyebrow="Settings" title={title} /><div className="form-stack">{children}</div></section>; }
function GeneralSettings() { const [settings, setSettings] = React.useState<GeneralSettingsState>({ application_name: "Social Hunter", public_url: "https://social-hunter.spunwebtechnology.com/", support_email: PAYPAL_EMAIL, default_plan: "growth", require_consent: true, normalized_evidence_only: true, high_cost_provider_approval: true, export_retention_days: 90 }); const [message, setMessage] = React.useState(""); const [busy, setBusy] = React.useState(false); React.useEffect(() => { api<GeneralSettingsState>("/api/admin/settings/general").then(setSettings).catch((err) => setMessage(err instanceof Error ? err.message : "Could not load settings")); }, []); async function save(e: React.FormEvent) { e.preventDefault(); setBusy(true); try { const saved = await api<GeneralSettingsState>("/api/admin/settings/general", { method: "PUT", body: JSON.stringify(settings) }); setSettings(saved); setMessage("General settings saved."); } catch (err) { setMessage(err instanceof Error ? err.message : "Save failed"); } finally { setBusy(false); } } return <form className="settings-grid" onSubmit={save}><SettingsPanel title="General settings"><label>Application name<input value={settings.application_name} onChange={(e) => setSettings({ ...settings, application_name: e.target.value })} /></label><label>Public URL<input value={settings.public_url} onChange={(e) => setSettings({ ...settings, public_url: e.target.value })} /></label><label>Support email<input value={settings.support_email} onChange={(e) => setSettings({ ...settings, support_email: e.target.value })} /></label><label>Default plan<select value={settings.default_plan} onChange={(e) => setSettings({ ...settings, default_plan: e.target.value })}><option value="starter">Starter</option><option value="growth">Growth</option><option value="operator">Operator</option></select></label><button className="primary-button" disabled={busy}><Settings size={18} />{busy ? "Saving" : "Save general settings"}</button>{message && <p className="success-state">{message}</p>}</SettingsPanel><SettingsPanel title="Search policy"><label><input type="checkbox" checked={settings.require_consent} onChange={(e) => setSettings({ ...settings, require_consent: e.target.checked })} /> Require consent confirmation before search</label><label><input type="checkbox" checked={settings.normalized_evidence_only} onChange={(e) => setSettings({ ...settings, normalized_evidence_only: e.target.checked })} /> Store normalized evidence only</label><label><input type="checkbox" checked={settings.high_cost_provider_approval} onChange={(e) => setSettings({ ...settings, high_cost_provider_approval: e.target.checked })} /> Require approval for high-cost providers</label><label>Export retention days<input type="number" min={1} value={settings.export_retention_days} onChange={(e) => setSettings({ ...settings, export_retention_days: Number(e.target.value) })} /></label></SettingsPanel></form>; }
function ApiSettings() { const [providers, setProviders] = React.useState<ProviderConfig[]>([]); const [keys, setKeys] = React.useState<ApiKeyReference[]>([]); const [gates, setGates] = React.useState<SourceGate[]>([]); const [message, setMessage] = React.useState(""); const [busy, setBusy] = React.useState(false); React.useEffect(() => { Promise.all([api<ProviderConfig[]>("/api/admin/provider-configs"), api<ApiKeyReference[]>("/api/admin/settings/api-keys"), api<SourceGate[]>("/api/admin/settings/source-gates")]).then(([p, k, g]) => { setProviders(p); setKeys(k); setGates(g); }).catch((err) => setMessage(err instanceof Error ? err.message : "Could not load provider configuration")); }, []); function updateKey(i: number, patch: Partial<ApiKeyReference>) { setKeys(keys.map((key, index) => index === i ? { ...key, ...patch } : key)); } function updateGate(sourceId: string, patch: Partial<SourceGate>) { setGates(gates.map((gate) => gate.source_id === sourceId ? { ...gate, ...patch } : gate)); } async function saveAll() { setBusy(true); try { const [savedKeys, savedGates] = await Promise.all([api<ApiKeyReference[]>("/api/admin/settings/api-keys", { method: "PUT", body: JSON.stringify(keys) }), api<SourceGate[]>("/api/admin/settings/source-gates", { method: "PUT", body: JSON.stringify(gates) })]); setKeys(savedKeys); setGates(savedGates); setMessage("API references and source gates saved."); } catch (err) { setMessage(err instanceof Error ? err.message : "Save failed"); } finally { setBusy(false); } } async function testKey(key: ApiKeyReference) { try { const result = await api<{ ok: boolean; message: string; connector_function: string }>("/api/admin/settings/api-keys/test", { method: "POST", body: JSON.stringify({ provider: key.provider, provider_id: key.provider_id, credential_type: key.credential_type, vault_reference: key.vault_reference }) }); setMessage(`${key.provider}: ${result.message} (${result.connector_function})`); } catch (err) { setMessage(err instanceof Error ? err.message : "Test failed"); } } const grouped = providers.reduce<Record<string, ProviderConfig[]>>((acc, provider) => { acc[provider.category] = acc[provider.category] ?? []; acc[provider.category].push(provider); return acc; }, {}); return <section className="admin-stack"><section className="content-panel"><SectionTitle eyebrow="Provider map" title="APIs wired to connector functions" copy="Every source is mapped to a backend function, source gate, Vault reference, and optional proxy route." /><div className="button-row no-pad"><button className="primary-button" type="button" onClick={saveAll} disabled={busy}><KeyRound size={18} />{busy ? "Saving" : "Save API configuration"}</button></div>{message && <p className="success-state">{message}</p>}</section>{Object.entries(grouped).map(([category, list]) => <section className="content-panel" key={category}><SectionTitle eyebrow="Source category" title={category.replaceAll("_", " ")} /><div className="provider-grid">{list.map((provider) => { const gate = gates.find((g) => g.source_id === provider.id); const providerKeys = keys.map((key, index) => ({ key, index })).filter(({ key }) => key.provider_id === provider.id); return <article className="provider-card" key={provider.id}><div className="provider-card-head"><div><h3>{provider.name}</h3><p>{provider.note || provider.terms_note}</p></div><span className={`status ${provider.status}`}>{provider.status.replaceAll("_", " ")}</span></div><dl><dt>Function</dt><dd>{provider.connector_function}</dd><dt>Returns</dt><dd>{provider.data_returned.join(", ")}</dd><dt>Proxy</dt><dd>{provider.proxy_route_supported ? "Allowed provider API egress route" : "Direct API or local route"}</dd></dl><label className="toggle-row"><input type="checkbox" checked={gate?.enabled ?? false} onChange={(e) => updateGate(provider.id, { enabled: e.target.checked })} /><span>Enable source gate</span><em>{gate?.tenant_plan ?? "operator"}</em></label><label className="toggle-row"><input type="checkbox" checked={gate?.requires_approval ?? true} onChange={(e) => updateGate(provider.id, { requires_approval: e.target.checked })} /><span>Require approval</span><em>control</em></label>{providerKeys.map(({ key, index }) => <div className="secret-row" key={`${key.provider_id}-${key.credential_type}`}><div><strong>{key.credential_type}</strong><span>{key.notes || "Vault reference required"}</span></div><input value={key.vault_reference} disabled={key.credential_type === "none"} placeholder="VAULT_REF_PROVIDER_KEY" onChange={(e) => updateKey(index, { vault_reference: e.target.value })} /><label className="inline-check"><input type="checkbox" checked={key.enabled} onChange={(e) => updateKey(index, { enabled: e.target.checked })} /> Enabled</label><button className="secondary-button compact" type="button" onClick={() => testKey(key)}>Test</button></div>)}</article>; })}</div></section>)}</section>; }
function ProxySettings() { const [settings, setSettings] = React.useState<ProxySettingsState>({ mode: "off", manual_entries: [], use_only_for_allowlisted_egress: true, disable_failed_proxies: true, require_admin_approval: false, health_check_interval_minutes: 30 }); const [routes, setRoutes] = React.useState<ProxyRouteRule[]>([]); const [importText, setImportText] = React.useState(""); const [targetUrl, setTargetUrl] = React.useState("https://api.ipify.org?format=json"); const [connectionResults, setConnectionResults] = React.useState<ProxyConnectionResult[]>([]); const [message, setMessage] = React.useState(""); const [busy, setBusy] = React.useState(false); const [testingConnections, setTestingConnections] = React.useState(false); React.useEffect(() => { Promise.all([api<ProxySettingsState>("/api/admin/settings/proxies"), api<ProxyRouteRule[]>("/api/admin/settings/proxies/routes")]).then(([s, r]) => { setSettings(s); setRoutes(r); setImportText(s.manual_entries.join("\n")); }).catch((err) => setMessage(err instanceof Error ? err.message : "Could not load proxy settings")); }, []); function currentEntries() { return importText.split(/\r?\n/).map((line) => line.trim()).filter((line) => line && !line.startsWith("#")); } function updateRoute(id: string, patch: Partial<ProxyRouteRule>) { setRoutes(routes.map((route) => route.id === id ? { ...route, ...patch } : route)); } async function importEntries() { try { const saved = await api<ProxySettingsState>("/api/admin/settings/proxies/import", { method: "POST", body: JSON.stringify({ entries_text: importText }) }); setSettings(saved); setMessage(`Imported ${saved.manual_entries.length} proxy entries.`); } catch (err) { setMessage(err instanceof Error ? err.message : "Proxy import failed"); } } async function testProxy() { try { const candidate = { ...settings, manual_entries: currentEntries() }; const result = await api<{ ok: boolean; tested: number; valid_format: number; invalid_entries: string[]; message: string }>("/api/admin/settings/proxies/test", { method: "POST", body: JSON.stringify(candidate) }); setMessage(`${result.message} Valid ${result.valid_format}/${result.tested}; invalid ${result.invalid_entries.length}.`); } catch (err) { setMessage(err instanceof Error ? err.message : "Proxy validation failed"); } } async function testConnections() { const entries = currentEntries(); setTestingConnections(true); setConnectionResults([]); setMessage(""); try { const result = await api<ProxyConnectionTestResponse>("/api/admin/settings/proxies/connection-test", { method: "POST", body: JSON.stringify({ entries, target_url: targetUrl, timeout_seconds: 8, concurrency: 4 }) }); setConnectionResults(result.results); setMessage(result.message); } catch (err) { setMessage(err instanceof Error ? err.message : "Proxy connection test failed"); } finally { setTestingConnections(false); } } async function saveAll() { setBusy(true); try { const nextSettings = { ...settings, manual_entries: currentEntries() }; const [savedSettings, savedRoutes] = await Promise.all([api<ProxySettingsState>("/api/admin/settings/proxies", { method: "PUT", body: JSON.stringify(nextSettings) }), api<ProxyRouteRule[]>("/api/admin/settings/proxies/routes", { method: "PUT", body: JSON.stringify(routes) })]); setSettings(savedSettings); setRoutes(savedRoutes); setImportText(savedSettings.manual_entries.join("\n")); setMessage("Proxy settings and routes saved."); } catch (err) { setMessage(err instanceof Error ? err.message : "Proxy save failed"); } finally { setBusy(false); } } const connected = connectionResults.filter((item) => item.ok).length; return <section className="settings-grid"><SettingsPanel title="Proxy configuration"><label>Mode<select value={settings.mode} onChange={(e) => setSettings({ ...settings, mode: e.target.value as ProxySettingsState["mode"] })}><option value="off">Off</option><option value="provider">Provider managed</option><option value="manual">Manual list</option></select></label><label>Manual import<textarea className="textarea-code" rows={7} value={importText} onChange={(e) => setImportText(e.target.value)} placeholder="host:port:user:password, one per line" /></label><label>Import by file<input type="file" accept=".txt,.csv" onChange={async (e) => { const file = e.target.files?.[0]; if (file) setImportText(await file.text()); }} /></label><label>Connection test URL<input value={targetUrl} onChange={(e) => setTargetUrl(e.target.value)} placeholder="https://api.ipify.org?format=json" /></label><div className="button-row no-pad"><button type="button" className="secondary-button compact" onClick={importEntries}><SlidersHorizontal size={18} />Import list</button><button type="button" className="secondary-button compact" onClick={testProxy}><Network size={18} />Validate format</button><button type="button" className="secondary-button compact" onClick={testConnections} disabled={testingConnections}><Network size={18} />{testingConnections ? "Testing" : "Test connections"}</button><button type="button" className="primary-button" onClick={saveAll} disabled={busy}><Network size={18} />{busy ? "Saving" : "Save proxy rules"}</button></div>{message && <p className="success-state">{message}</p>}{connectionResults.length > 0 && <div className="proxy-test-results"><div className="metric-strip cards"><Metric label="Tested" value={String(connectionResults.length)} /><Metric label="Connected" value={String(connected)} /><Metric label="Needs review" value={String(connectionResults.length - connected)} /></div><div className="table-wrap"><table><thead><tr><th>Proxy</th><th>Status</th><th>Latency</th><th>HTTP</th><th>Result</th></tr></thead><tbody>{connectionResults.map((result) => <tr key={`${result.index}-${result.proxy}`}><td>{result.proxy}</td><td><span className={`status ${result.status === "connected" ? "ready" : result.status === "invalid_format" ? "error" : "needs_api_key"}`}>{result.status.replaceAll("_", " ")}</span></td><td>{result.latency_ms ? `${result.latency_ms} ms` : "-"}</td><td>{result.http_status ?? "-"}</td><td>{result.error || "Connected"}</td></tr>)}</tbody></table></div></div>}</SettingsPanel><SettingsPanel title="Proxy rules"><label><input type="checkbox" checked={settings.use_only_for_allowlisted_egress} onChange={(e) => setSettings({ ...settings, use_only_for_allowlisted_egress: e.target.checked })} /> Use proxies only for allowlisted provider egress</label><label><input type="checkbox" checked={settings.disable_failed_proxies} onChange={(e) => setSettings({ ...settings, disable_failed_proxies: e.target.checked })} /> Disable failed proxies after repeated connection errors</label><label><input type="checkbox" checked={settings.require_admin_approval} onChange={(e) => setSettings({ ...settings, require_admin_approval: e.target.checked })} /> Require admin approval before enabling a proxy list</label><label>Health check interval<select value={settings.health_check_interval_minutes} onChange={(e) => setSettings({ ...settings, health_check_interval_minutes: Number(e.target.value) })}><option value={15}>15 minutes</option><option value={30}>30 minutes</option><option value={60}>60 minutes</option></select></label>{routes.map((route) => <article className="route-card" key={route.id}><label className="toggle-row"><input type="checkbox" checked={route.enabled} onChange={(e) => updateRoute(route.id, { enabled: e.target.checked })} /><span>{route.label}</span><em>{route.category}</em></label><label className="toggle-row"><input type="checkbox" checked={route.proxy_required} onChange={(e) => updateRoute(route.id, { proxy_required: e.target.checked })} /><span>Require proxy for this route</span><em>{route.provider_ids.length} providers</em></label><p>{route.note}</p><small>{route.allowed_domains.join(", ")}</small></article>)}</SettingsPanel></section>; }
function ContactMail() { const [msgs, setMsgs] = React.useState<ContactSubmissionRecord[]>([]); const [error, setError] = React.useState(""); React.useEffect(() => { api<ContactSubmissionRecord[]>("/api/admin/contact-submissions").then(setMsgs).catch((err) => setError(err instanceof Error ? err.message : "Could not load contact submissions")); }, []); return <section className="content-panel"><SectionTitle eyebrow="Mail" title="Contact form submissions" copy="Route public contact and signup requests into this mailbox." />{error && <p className="error-state">{error}</p>}<div className="table-wrap"><table><thead><tr><th>Name</th><th>Email</th><th>Company</th><th>Message</th><th>Status</th></tr></thead><tbody>{msgs.length === 0 && <tr><td colSpan={5}>No submissions yet.</td></tr>}{msgs.map((m) => <tr key={m.id}><td>{m.name}</td><td>{m.email}</td><td>{m.company}</td><td>{m.message}</td><td><span className={`status ${m.status}`}>{m.status}</span></td></tr>)}</tbody></table></div></section>; }
function UsersPage() { return <section className="content-panel"><SectionTitle eyebrow="Users" title="Members and roles" copy="Manage tenant access, roles, and dashboard permissions." /><div className="table-wrap"><table><thead><tr><th>User</th><th>Role</th><th>Plan</th><th>Status</th></tr></thead><tbody>{[{ n: "Ryan", r: "Owner", p: "Operator", s: "active" }, { n: "Demo Analyst", r: "Analyst", p: "Growth", s: "pending" }].map((u) => <tr key={u.n}><td>{u.n}</td><td>{u.r}</td><td>{u.p}</td><td><span className={`status ${u.s}`}>{u.s}</span></td></tr>)}</tbody></table></div></section>; }
function BillingPage() { const [settings, setSettings] = React.useState<PayPalSettingsState>({ receiver_email: PAYPAL_EMAIL, webhook_secret_ref: "VAULT_REF_PAYPAL_WEBHOOK_SECRET", subscriptions_enabled: false, webhook_verified: false, currency: "USD", checkout_mode: "paypal_button", billing_contact_email: PAYPAL_EMAIL, terms_url: "https://social-hunter.spunwebtechnology.com/#pricing", success_url: "https://social-hunter.spunwebtechnology.com/members/", cancel_url: "https://social-hunter.spunwebtechnology.com/#pricing", plans: defaultBillingPlans }); const [message, setMessage] = React.useState(""); const [busy, setBusy] = React.useState(false); React.useEffect(() => { api<PayPalSettingsState>("/api/admin/settings/paypal").then(setSettings).catch((err) => setMessage(err instanceof Error ? err.message : "Could not load billing settings")); }, []); function updateSettings(patch: Partial<PayPalSettingsState>) { setSettings({ ...settings, ...patch }); } function updatePlan(index: number, patch: Partial<BillingPlan>) { setSettings({ ...settings, plans: settings.plans.map((plan, i) => i === index ? { ...plan, ...patch } : plan) }); } function updateService(planIndex: number, serviceIndex: number, value: string) { updatePlan(planIndex, { services: settings.plans[planIndex].services.map((service, i) => i === serviceIndex ? value : service) }); } function addService(planIndex: number) { updatePlan(planIndex, { services: [...settings.plans[planIndex].services, "New included service"] }); } function removeService(planIndex: number, serviceIndex: number) { updatePlan(planIndex, { services: settings.plans[planIndex].services.filter((_, i) => i !== serviceIndex) }); } function addPlan() { const next = settings.plans.length + 1; setSettings({ ...settings, plans: [...settings.plans, { id: `custom-${next}`, name: `Custom ${next}`, amount: 99, currency: settings.currency || "USD", interval: "month", monthly_search_limit: 500, export_enabled: true, api_access_enabled: false, description: "Custom configurable Social Hunter plan.", services: ["Dashboard access"], enabled: true, public: false, paypal_item_name: `Social Hunter Custom ${next} Plan`, sort_order: next * 10 }] }); } function removePlan(index: number) { setSettings({ ...settings, plans: settings.plans.filter((_, i) => i !== index) }); } async function save(e: React.FormEvent) { e.preventDefault(); setBusy(true); setMessage(""); try { const saved = await api<PayPalSettingsState>("/api/admin/settings/paypal", { method: "PUT", body: JSON.stringify(settings) }); setSettings(saved); setMessage("Billing configuration saved. Public pricing and checkout now use these values."); } catch (err) { setMessage(err instanceof Error ? err.message : "Billing save failed"); } finally { setBusy(false); } } return <form className="admin-stack" onSubmit={save}><section className="content-panel"><SectionTitle eyebrow="Billing" title="PayPal and plan configuration" copy="Configure public prices, plan descriptions, included services, limits, checkout behavior, and billing status." /><div className="billing-settings-grid"><label>PayPal receiver email<input value={settings.receiver_email} onChange={(e) => updateSettings({ receiver_email: e.target.value })} /></label><label>Billing contact email<input value={settings.billing_contact_email} onChange={(e) => updateSettings({ billing_contact_email: e.target.value })} /></label><label>Currency<input value={settings.currency} maxLength={3} onChange={(e) => updateSettings({ currency: e.target.value.toUpperCase() })} /></label><label>Checkout mode<select value={settings.checkout_mode} onChange={(e) => updateSettings({ checkout_mode: e.target.value as PayPalSettingsState["checkout_mode"] })}><option value="paypal_button">PayPal button</option><option value="subscription">Subscription</option><option value="manual_invoice">Manual invoice</option></select></label><label>Webhook secret Vault ref<input value={settings.webhook_secret_ref} onChange={(e) => updateSettings({ webhook_secret_ref: e.target.value })} /></label><label>Terms URL<input value={settings.terms_url} onChange={(e) => updateSettings({ terms_url: e.target.value })} /></label><label>Success URL<input value={settings.success_url} onChange={(e) => updateSettings({ success_url: e.target.value })} /></label><label>Cancel URL<input value={settings.cancel_url} onChange={(e) => updateSettings({ cancel_url: e.target.value })} /></label><label className="toggle-row"><input type="checkbox" checked={settings.subscriptions_enabled} onChange={(e) => updateSettings({ subscriptions_enabled: e.target.checked })} /><span>Subscriptions enabled</span><em>PayPal</em></label><label className="toggle-row"><input type="checkbox" checked={settings.webhook_verified} onChange={(e) => updateSettings({ webhook_verified: e.target.checked })} /><span>Webhook verified</span><em>Status</em></label></div><div className="button-row no-pad"><button className="secondary-button compact" type="button" onClick={addPlan}><CreditCard size={18} />Add plan</button><button className="primary-button" disabled={busy}><CreditCard size={18} />{busy ? "Saving billing" : "Save billing configuration"}</button></div>{message && <p className="success-state">{message}</p>}</section><section className="billing-plan-list">{settings.plans.map((plan, index) => <article className="content-panel billing-plan-editor" key={`${plan.id}-${index}`}><div className="provider-card-head"><div><span className="eyebrow">Plan</span><h3>{plan.name || plan.id}</h3></div><button className="secondary-button compact" type="button" onClick={() => removePlan(index)}>Remove</button></div><div className="billing-plan-grid"><label>Plan ID<input value={plan.id} onChange={(e) => updatePlan(index, { id: e.target.value.toLowerCase().replace(/[^a-z0-9-]/g, "-") })} /></label><label>Name<input value={plan.name} onChange={(e) => updatePlan(index, { name: e.target.value })} /></label><label>Price<input type="number" min={0} step="0.01" value={plan.amount} onChange={(e) => updatePlan(index, { amount: Number(e.target.value) })} /></label><label>Currency<input maxLength={3} value={plan.currency} onChange={(e) => updatePlan(index, { currency: e.target.value.toUpperCase() })} /></label><label>Interval<select value={plan.interval} onChange={(e) => updatePlan(index, { interval: e.target.value as BillingPlan["interval"] })}><option value="month">Monthly</option><option value="year">Yearly</option><option value="one_time">One time</option></select></label><label>Monthly search limit<input type="number" min={0} value={plan.monthly_search_limit} onChange={(e) => updatePlan(index, { monthly_search_limit: Number(e.target.value) })} /></label><label>PayPal item name<input value={plan.paypal_item_name} onChange={(e) => updatePlan(index, { paypal_item_name: e.target.value })} /></label><label>Sort order<input type="number" value={plan.sort_order} onChange={(e) => updatePlan(index, { sort_order: Number(e.target.value) })} /></label><label className="wide-field">Description<textarea rows={3} value={plan.description} onChange={(e) => updatePlan(index, { description: e.target.value })} /></label><label className="toggle-row"><input type="checkbox" checked={plan.enabled} onChange={(e) => updatePlan(index, { enabled: e.target.checked })} /><span>Enabled</span><em>Internal</em></label><label className="toggle-row"><input type="checkbox" checked={plan.public} onChange={(e) => updatePlan(index, { public: e.target.checked })} /><span>Public pricing</span><em>Landing</em></label><label className="toggle-row"><input type="checkbox" checked={plan.export_enabled} onChange={(e) => updatePlan(index, { export_enabled: e.target.checked })} /><span>Exports</span><em>Feature</em></label><label className="toggle-row"><input type="checkbox" checked={plan.api_access_enabled} onChange={(e) => updatePlan(index, { api_access_enabled: e.target.checked })} /><span>API access</span><em>Feature</em></label></div><div className="service-editor"><div className="provider-card-head"><strong>Included services</strong><button className="secondary-button compact" type="button" onClick={() => addService(index)}>Add service</button></div>{plan.services.map((service, serviceIndex) => <div className="service-row" key={`${plan.id}-service-${serviceIndex}`}><input value={service} onChange={(e) => updateService(index, serviceIndex, e.target.value)} /><button className="secondary-button compact" type="button" onClick={() => removeService(index, serviceIndex)}>Remove</button></div>)}</div></article>)}</section></form>; }
function AuditPage() { const [events, setEvents] = React.useState<AuditEvent[]>([]); const [error, setError] = React.useState(""); React.useEffect(() => { api<AuditEvent[]>("/api/admin/audit").then(setEvents).catch((err) => setError(err instanceof Error ? err.message : "Could not load audit events")); }, []); return <section className="content-panel"><SectionTitle eyebrow="Audit" title="Audit and operations" copy="Track searches, exports, admin settings, API-key tests, and proxy changes." />{error && <p className="error-state">{error}</p>}<div className="table-wrap"><table><thead><tr><th>Action</th><th>Actor</th><th>Status</th><th>Metadata</th></tr></thead><tbody>{events.length === 0 && <tr><td colSpan={4}>No audit events yet.</td></tr>}{events.map((event, idx) => <tr key={idx}><td>{event.action ?? "event"}</td><td>{event.actor ?? "system"}</td><td><span className={`status ${event.status ?? "reviewed"}`}>{event.status ?? "recorded"}</span></td><td>{Object.entries(event).filter(([key]) => !["action", "actor", "status"].includes(key)).map(([key, value]) => `${key}: ${value}`).join(" | ")}</td></tr>)}</tbody></table></div></section>; }
function ContactForm() { const [form, setForm] = React.useState({ name: "", email: "", company: "", message: "" }); const [status, setStatus] = React.useState(""); async function submit(e: React.FormEvent) { e.preventDefault(); try { await api<ContactSubmissionRecord>("/api/contact", { method: "POST", body: JSON.stringify(form) }); setStatus("Request sent."); setForm({ name: "", email: "", company: "", message: "" }); } catch (err) { setStatus(err instanceof Error ? err.message : "Request failed"); } } return <form className="contact-form" onSubmit={submit}><label>Name<input value={form.name} onChange={(e) => setForm({ ...form, name: e.target.value })} placeholder="Your name" /></label><label>Email<input value={form.email} onChange={(e) => setForm({ ...form, email: e.target.value })} type="email" placeholder="you@company.com" /></label><label>Company<input value={form.company} onChange={(e) => setForm({ ...form, company: e.target.value })} placeholder="Company" /></label><label>Message<textarea value={form.message} onChange={(e) => setForm({ ...form, message: e.target.value })} rows={5} placeholder="Tell us what you need Social Hunter to help with." /></label><button className="primary-button full"><Mail size={18} />Send request</button>{status && <p className="success-state">{status}</p>}</form>; }
ReactDOM.createRoot(document.getElementById("root")!).render(<App />);
